def generate_queries(state: ResearchState) -> dict:
    # Reads: question
    # Writes: search_queries
    queries = [
        state["question"],
        f"background on {state['question']}",
        f"{state['question']} recent developments",
    ]
    return {"search_queries": queries}

def increment_iteration(state: ResearchState) -> dict:
    return {"iteration": state["iteration"] + 1}

import operator
from typing import Annotated, TypedDict

class AgentState(TypedDict):
    # operator.add on lists means: new_value = existing + update
    # So returning {"messages": [new_msg]} APPENDS, not replaces
    messages: Annotated[list, operator.add]
    current_tool: str   # last-write wins (no reducer)

def call_llm(state: AgentState) -> dict:
    from langchain_core.messages import AIMessage
    response = AIMessage(content="I'll look that up for you.")
    # This APPENDS to state["messages"], not replaces
    return {"messages": [response]}

def call_tool(state: AgentState) -> dict:
    from langchain_core.messages import ToolMessage
    result = ToolMessage(content="Search result: ...", tool_call_id="123")
    return {"messages": [result], "current_tool": "search"}

from typing import Annotated, TypedDict

def keep_unique(existing: list, update: list) -> list:
    """Append update items, skipping duplicates."""
    seen = set(existing)
    return existing + [x for x in update if x not in seen]

class DeduplicatingState(TypedDict):
    sources: Annotated[list[str], keep_unique]

def fetch_sources(state: DeduplicatingState) -> dict:
    return {"sources": ["doc_A", "doc_B", "doc_A"]}   # doc_A won't duplicate

# After two runs: state["sources"] == ["doc_A", "doc_B"], not ["doc_A", "doc_B", "doc_A"]

from typing import TypedDict
from langgraph.graph import StateGraph, END

class PublicState(TypedDict):
    question: str
    final_answer: str

class SearchOutput(TypedDict):
    question: str
    raw_results: list[str]   # private — won't be in PublicState

class SynthesisInput(TypedDict):
    question: str
    raw_results: list[str]

# Node that outputs to a private schema
def search(state: PublicState) -> SearchOutput:
    return {
        "question": state["question"],
        "raw_results": ["result A", "result B"],
    }

# Node that reads the private schema
def synthesize(state: SynthesisInput) -> dict:
    answer = " ".join(state["raw_results"])
    return {"final_answer": answer}
